INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('El Padrino', 'Francis Ford Coppola', 1972, 'Crimen/Drama', 'El patriarca de una dinastía del crimen organizado transfiere el control de su imperio clandestino a su hijo.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('Pulp Fiction', 'Quentin Tarantino', 1994, 'Crimen/Drama', 'Las vidas de dos mafiosos, un boxeador y una pareja de bandidos se entrelazan en cuatro historias de violencia y redención.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('El Señor de los Anillos: La Comunidad del Anillo', 'Peter Jackson', 2001, 'Fantasía/Aventura', 'Un hobbit de la Comarca y ocho compañeros emprenden un viaje para destruir el poderoso Anillo Único.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('Matrix', 'Lana y Lilly Wachowski', 1999, 'Ciencia Ficción/Acción', 'Un hacker informático descubre la verdadera naturaleza de su realidad y su papel en la guerra contra sus controladores.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('Inception', 'Christopher Nolan', 2010, 'Ciencia Ficción/Acción', 'Un ladrón que roba secretos corporativos usando tecnología para compartir sueños recibe la tarea de plantar una idea en una mente.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('Forrest Gump', 'Robert Zemeckis', 1994, 'Drama/Comedia', 'Eventos históricos de Estados Unidos se desarrollan a través de la perspectiva de un hombre noble de Alabama con un bajo coeficiente intelectual.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('El Viaje de Chihiro', 'Hayao Miyazaki', 2001, 'Animación/Fantasía', 'Durante una mudanza, una niña de 10 años deambula por un mundo gobernado por dioses, brujas y espíritus.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('Parásitos', 'Bong Joon Ho', 2019, 'Suspenso/Comedia Negra', 'La discriminación y la codicia amenazan la relación simbiótica entre la acaudalada familia Park y el indigente clan Kim.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('Interstellar', 'Christopher Nolan', 2014, 'Ciencia Ficción/Drama', 'Un equipo de exploradores viaja a través de un agujero de gusano en el espacio en un intento por salvar a la humanidad.');
INSERT INTO peliculas (titulo, director, año, genero, sinopsis) 
    VALUES ('Volver al Futuro', 'Robert Zemeckis', 1985, 'Ciencia Ficción/Comedia', 'Un adolescente es enviado accidentalmente treinta años en el pasado en un automóvil DeLorean modificado para viajar en el tiempo.');

